SELECT [Sales Header].[Document Type], [Sales Header].[Document Date], Format$([DOCUMENT DATE],"mm/dd") AS mesegiorno, [Sales Header].[Salesperson Code], [Sales Header].[Sell-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].[Ship-to City], [Sales Header].No_ AS OrderNo, [Sales Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Header].[selling season code] AS Stagione, Item.[LINE CODE], Item.[COLLECTION CODE], Item.DESCRIPTION, Item.[DESCRIPTION 2], [Sales Line].[MODEL ITEM NO_], [Sales Line].[constant variable code] AS COLOR, [Variable Code].Description AS ColorDecription, Item.[PRODUCT SEX], Val([no_ of pairs]) AS qty, IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount]))) AS ValueSold, [Sales Line].[DELETE REASON]
FROM ([Sales Header] INNER JOIN (Item INNER JOIN [Sales Line] ON Item.No_ = [Sales Line].No_) ON ([Sales Header].[Document Type] = [Sales Line].[Document Type]) AND ([Sales Header].No_ = [Sales Line].[Document No_])) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])
WHERE ((([Sales Header].[Document Type])=1) AND (([Sales Header].[selling season code])="E20" Or ([Sales Header].[selling season code])="E21" Or ([Sales Header].[selling season code])="E22" Or ([Sales Header].[selling season code])="E23" Or ([Sales Header].[selling season code])="E24" Or ([Sales Header].[selling season code])="E25") AND (([Sales Line].Type)=19 Or ([Sales Line].Type)=20));

